const files = $input.all().map(item => item.json);

const analysis = {
  totalFiles: files.length,
  fileTypes: {},
  directories: [],
  configFiles: [],
  sourceFiles: [],
  hasPackageJson: false,
  hasDockerfile: false,
  hasCI: false,
  hasAndroidConfig: false,
  hasWebConfig: false,
  hasWindowsConfig: false
};

files.forEach(file => {
  if (file.type === "dir") {
    analysis.directories.push(file.name);
  } else {
    const ext = file.name.split(".").pop();
    analysis.fileTypes[ext] = (analysis.fileTypes[ext] || 0) + 1;

    if (file.name === "package.json" || file.path === "package.json") {
      analysis.hasPackageJson = true;
      analysis.configFiles.push(file.name);
    }
    if (file.name === "Dockerfile" || file.path === "Dockerfile") {
      analysis.hasDockerfile = true;
      analysis.configFiles.push(file.name);
    }
    if (file.name.includes(".yml") || file.name.includes(".yaml") || file.path.includes(".github/workflows")) {
      analysis.hasCI = true;
      analysis.configFiles.push(file.name);
    }
    if (file.name === "android" || file.path.includes("android") || file.name.includes("build.gradle")) {
      analysis.hasAndroidConfig = true;
    }
    if (file.name === "public" || file.path.includes("public") || file.name === "index.html") {
      analysis.hasWebConfig = true;
    }
    if (file.name.includes("electron") || file.path.includes("electron-builder")) {
      analysis.hasWindowsConfig = true;
    }
    if (ext === "js" || ext === "ts" || ext === "jsx" || ext === "tsx") {
      analysis.sourceFiles.push(file.name);
    }
  }
});

analysis.needsReview = !analysis.hasPackageJson || !analysis.hasDockerfile || !analysis.hasCI || !analysis.hasAndroidConfig || !analysis.hasWebConfig || !analysis.hasWindowsConfig;
analysis.reviewNotes = [];

if (!analysis.hasPackageJson) {
  analysis.reviewNotes.push("❌ Missing package.json - dependencies not managed");
}
if (!analysis.hasDockerfile) {
  analysis.reviewNotes.push("❌ Missing Dockerfile - containerization not configured");
}
if (!analysis.hasCI) {
  analysis.reviewNotes.push("❌ Missing CI/CD configuration - automated deployment not set up");
}
if (!analysis.hasAndroidConfig) {
  analysis.reviewNotes.push("❌ Missing Android build configuration");
}
if (!analysis.hasWebConfig) {
  analysis.reviewNotes.push("❌ Missing web application configuration");
}
if (!analysis.hasWindowsConfig) {
  analysis.reviewNotes.push("❌ Missing Windows build configuration");
}

return [{ json: analysis }];

