parameters.jsCode:
const analysis = $("Analyze Project Structure").first().json;
const existingFiles = $input.all().map(item => item.json);
const configs = [];

const fileExists = (path) => existingFiles.some(f => f.path === path);
const getFileSha = (path) => {
  const file = existingFiles.find(f => f.path === path);
  return file ? file.sha : null;
};

if (!analysis.hasCI) {
  const ciPath = ".github/workflows/build-deploy.yml";
  const ciContent = "name: Build and Deploy All Platforms

on:
  push:
    branches: [ main ]
  workflow_dispatch:

jobs:
  build-android:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - name: Setup Java
        uses: actions/setup-java@v4
        with:
          distribution: temurin
          java-version: 17
      - name: Setup Android SDK
        uses: android-actions/setup-android@v3
      - name: Create Android Project Structure
        run: |
          mkdir -p android/app/src/main/java/com/medcenter/app
          mkdir -p android/app/src/main/res
      - name: Build Android APK
        run: |
          cd android
          chmod +x gradlew || echo Gradlew not found
          ./gradlew assembleRelease || echo Build skipped
      - name: Upload APK
        uses: actions/upload-artifact@v4
        with:
          name: android-apk
          path: android/app/build/outputs/apk/release/*.apk
          if-no-files-found: warn

  build-web:
    runs-on: ubuntu-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with:
          node-version: 20
      - run: npm install || echo No package.json
      - run: npm run build:web || npm run build || echo No build script
      - name: Deploy to GitHub Pages
        uses: peaceiris/actions-gh-pages@v4
        if: hashFiles(dist/**) != ""
        with:
          github_token: \${{ secrets.GITHUB_TOKEN }}
          publish_dir: ./dist

  build-windows:
    runs-on: windows-latest
    steps:
      - uses: actions/checkout@v4
      - uses: actions/setup-node@v4
        with:
          node-version: 20
      - run: npm install || echo No package.json
      - run: npm run build:windows || npm run build || echo No build script
      - name: Upload Windows Installer
        uses: actions/upload-artifact@v4
        with:
          name: windows-installer
          path: dist/*.exe
          if-no-files-found: warn";
  configs.push({
    filename: "build-deploy.yml",
    content: ciContent,
    path: ciPath,
    sha: getFileSha(ciPath),
    isEdit: fileExists(ciPath)
  });
}

if (!analysis.hasAndroidConfig) {
  const androidBuildPath = "android/build.gradle";
  const androidBuildContent = "buildscript {
    repositories {
        google()
        mavenCentral()
    }
    dependencies {
        classpath "com.android.tools.build:gradle:8.0.0"
    }
}

allprojects {
    repositories {
        google()
        mavenCentral()
    }
}";
  configs.push({
    filename: "build.gradle",
    content: androidBuildContent,
    path: androidBuildPath,
    sha: getFileSha(androidBuildPath),
    isEdit: fileExists(androidBuildPath)
  });

  const androidAppBuildPath = "android/app/build.gradle";
  const androidAppContent = "apply plugin: "com.android.application"

android {
    namespace "com.medcenter.app"
    compileSdkVersion 33
    defaultConfig {
        applicationId "com.medcenter.app"
        minSdkVersion 21
        targetSdkVersion 33
        versionCode 1
        versionName "1.0"
    }
    buildTypes {
        release {
            minifyEnabled false
            proguardFiles getDefaultProguardFile("proguard-android-optimize.txt"), "proguard-rules.pro"
        }
    }
}

dependencies {
    implementation "androidx.appcompat:appcompat:1.6.1"
    implementation "com.google.android.material:material:1.9.0"
}";
  configs.push({
    filename: "app-build.gradle",
    content: androidAppContent,
    path: androidAppBuildPath,
    sha: getFileSha(androidAppBuildPath),
    isEdit: fileExists(androidAppBuildPath)
  });

  const androidManifestPath = "android/app/src/main/AndroidManifest.xml";
  const androidManifestContent = "<?xml version="1.0" encoding="utf-8"?>
<manifest xmlns:android="http://schemas.android.com/apk/res/android">
    <application
        android:allowBackup="true"
        android:icon="@mipmap/ic_launcher"
        android:label="MedCenter"
        android:theme="@style/Theme.AppCompat.Light">
        <activity
            android:name=".MainActivity"
            android:exported="true">
            <intent-filter>
                <action android:name="android.intent.action.MAIN" />
                <category android:name="android.intent.category.LAUNCHER" />
            </intent-filter>
        </activity>
    </application>
</manifest>";
  configs.push({
    filename: "AndroidManifest.xml",
    content: androidManifestContent,
    path: androidManifestPath,
    sha: getFileSha(androidManifestPath),
    isEdit: fileExists(androidManifestPath)
  });

  const gradleWrapperPath = "android/gradle/wrapper/gradle-wrapper.properties";
  const gradleWrapperContent = "distributionBase=GRADLE_USER_HOME
distributionPath=wrapper/dists
distributionUrl=https\://services.gradle.org/distributions/gradle-8.0-bin.zip
zipStoreBase=GRADLE_USER_HOME
zipStorePath=wrapper/dists";
  configs.push({
    filename: "gradle-wrapper.properties",
    content: gradleWrapperContent,
    path: gradleWrapperPath,
    sha: getFileSha(gradleWrapperPath),
    isEdit: fileExists(gradleWrapperPath)
  });
}

if (!analysis.hasWindowsConfig) {
  const electronPath = "electron-builder.json";
  const electronContent = JSON.stringify({
    "appId": "com.medcenter.app",
    "productName": "MedCenter",
    "directories": {
      "output": "dist"
    },
    "win": {
      "target": "nsis",
      "icon": "icon.ico"
    }
  }, null, 2);
  configs.push({
    filename: "electron-builder.json",
    content: electronContent,
    path: electronPath,
    sha: getFileSha(electronPath),
    isEdit: fileExists(electronPath)
  });
}

if (configs.length === 0) {
  return [{ json: { status: "no_files_needed", message: "All required files already exist" } }];
}

return configs.map(c => ({ json: c }));
